
UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=Rz95ky4G_E8', conteudo_texto = '<h2>Resistência dos Materiais</h2><p>Tensões, deformações e dimensionamento de elementos estruturais.</p><h3>📐 Conceitos Fundamentais</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Conceito</th><th style=''padding:10px;border:1px solid #ddd;''>Símbolo</th><th style=''padding:10px;border:1px solid #ddd;''>Fórmula</th><th style=''padding:10px;border:1px solid #ddd;''>Unidade</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Tensão Normal</strong></td><td style=''padding:10px;border:1px solid #ddd;''>σ (sigma)</td><td style=''padding:10px;border:1px solid #ddd;''>σ = F / A</td><td style=''padding:10px;border:1px solid #ddd;''>Pa, MPa</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Tensão Cisalhante</strong></td><td style=''padding:10px;border:1px solid #ddd;''>τ (tau)</td><td style=''padding:10px;border:1px solid #ddd;''>τ = V / A</td><td style=''padding:10px;border:1px solid #ddd;''>Pa, MPa</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Deformação</strong></td><td style=''padding:10px;border:1px solid #ddd;''>ε (epsilon)</td><td style=''padding:10px;border:1px solid #ddd;''>ε = ΔL / L₀</td><td style=''padding:10px;border:1px solid #ddd;''>adimensional</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Módulo de Elasticidade</strong></td><td style=''padding:10px;border:1px solid #ddd;''>E</td><td style=''padding:10px;border:1px solid #ddd;''>E = σ / ε</td><td style=''padding:10px;border:1px solid #ddd;''>GPa</td></tr></table></div><h3>📊 Lei de Hooke</h3><div style=''background:#d4edda;padding:20px;border-radius:8px;margin:15px 0;text-align:center;''><h3 style=''color:#28a745;''>σ = E × ε</h3><p>Tensão = Módulo de Elasticidade × Deformação</p><p><em>Válida apenas no regime elástico (linear)</em></p></div><h3>📈 Diagrama Tensão-Deformação</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Região</th><th style=''padding:10px;border:1px solid #ddd;''>Característica</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Elástica</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Deformação reversível, Lei de Hooke válida</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Escoamento</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Deformação plástica inicia (σy)</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Encruamento</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Material endurece até tensão máxima</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Estricção</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Redução de área até ruptura</td></tr></table></div><h3>🔩 Tipos de Solicitações</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:150px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>Tração</strong><p>Força que alonga</p></div><div style=''flex:1;min-width:150px;background:#f8d7da;padding:15px;border-radius:8px;text-align:center;''><strong>Compressão</strong><p>Força que encurta</p></div><div style=''flex:1;min-width:150px;background:#fff3cd;padding:15px;border-radius:8px;text-align:center;''><strong>Cisalhamento</strong><p>Força paralela</p></div><div style=''flex:1;min-width:150px;background:#d1ecf1;padding:15px;border-radius:8px;text-align:center;''><strong>Flexão</strong><p>Momento fletor</p></div><div style=''flex:1;min-width:150px;background:#e8f4f8;padding:15px;border-radius:8px;text-align:center;''><strong>Torção</strong><p>Momento torçor</p></div></div><h3>📐 Flexão de Vigas</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;''><h4>Tensão na Flexão:</h4><p style=''text-align:center;font-size:1.2em;''><strong>σ = M × y / I</strong></p><p>M = momento fletor | y = distância do eixo neutro | I = momento de inércia</p><h4>Momento de Inércia (seções comuns):</h4><ul><li><strong>Retângulo:</strong> I = b × h³ / 12</li><li><strong>Círculo:</strong> I = π × d⁴ / 64</li></ul></div><h3>🔄 Torção</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p style=''text-align:center;font-size:1.2em;''><strong>τ = T × r / J</strong></p><p>T = torque | r = raio | J = momento polar de inércia</p><p><strong>Eixo circular:</strong> J = π × d⁴ / 32</p></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Na flexão, a <strong>tensão máxima</strong> ocorre nas fibras mais afastadas do eixo neutro (y máximo). O eixo neutro tem tensão ZERO!</p></div>' WHERE titulo = 'Resumo: Resistência dos Materiais';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=fqBu9Y_K6zE', conteudo_texto = '<h2>Elementos de Máquinas</h2><p>Engrenagens, eixos, rolamentos e componentes mecânicos.</p><h3>⚙️ Classificação dos Elementos</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>Fixação</h4><ul><li>Parafusos</li><li>Porcas</li><li>Rebites</li><li>Soldas</li></ul></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>Transmissão</h4><ul><li>Engrenagens</li><li>Correias</li><li>Correntes</li><li>Acoplamentos</li></ul></div><div style=''flex:1;min-width:200px;background:#d1ecf1;padding:15px;border-radius:8px;''><h4>Apoio</h4><ul><li>Rolamentos</li><li>Mancais</li><li>Guias</li></ul></div></div><h3>⚙️ Engrenagens</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>Característica</th><th style=''padding:10px;border:1px solid #ddd;''>Aplicação</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Cilíndrica Reta</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Dentes paralelos ao eixo</td><td style=''padding:10px;border:1px solid #ddd;''>Baixa velocidade, simples</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Cilíndrica Helicoidal</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Dentes inclinados</td><td style=''padding:10px;border:1px solid #ddd;''>Alta velocidade, silenciosa</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Cônica</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Eixos concorrentes (90°)</td><td style=''padding:10px;border:1px solid #ddd;''>Mudança de direção</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Sem-fim / Coroa</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Alta redução, irreversível</td><td style=''padding:10px;border:1px solid #ddd;''>Elevadores, guinchos</td></tr></table></div><h4>Relação de Transmissão:</h4><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;text-align:center;''><h4 style=''color:#28a745;''>i = Z₂/Z₁ = n₁/n₂ = D₂/D₁</h4><p>Z = número de dentes | n = rotação | D = diâmetro</p></div><h3>🔩 Rolamentos</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tipo</th><th style=''padding:10px;border:1px solid #ddd;''>Carga</th><th style=''padding:10px;border:1px solid #ddd;''>Características</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Rígido de Esferas</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Radial + axial leve</td><td style=''padding:10px;border:1px solid #ddd;''>Mais comum, versátil</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Rolos Cilíndricos</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Radial pesada</td><td style=''padding:10px;border:1px solid #ddd;''>Alta capacidade</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Rolos Cônicos</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Radial + axial</td><td style=''padding:10px;border:1px solid #ddd;''>Cubos de rodas</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Axial (Escora)</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Axial pura</td><td style=''padding:10px;border:1px solid #ddd;''>Cargas verticais</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Autocompensador</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Radial + desalinhamento</td><td style=''padding:10px;border:1px solid #ddd;''>Eixos flexíveis</td></tr></table></div><h3>🔗 Correias e Correntes</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>Correias</h4><ul><li><strong>Plana:</strong> Baixa potência</li><li><strong>V:</strong> Automotivo, industrial</li><li><strong>Sincronizadora:</strong> Timing, sem escorregamento</li></ul></div><div style=''flex:1;min-width:200px;background:#d1ecf1;padding:15px;border-radius:8px;''><h4>Correntes</h4><ul><li><strong>Rolos:</strong> Bicicletas, motocicletas</li><li><strong>Engrenagem:</strong> Alta potência</li><li>Sem escorregamento</li></ul></div></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Na transmissão por engrenagens: se Z₂ > Z₁, temos <strong>redução</strong> (velocidade diminui, torque aumenta). Inverso = multiplicação!</p></div>' WHERE titulo = 'Resumo: Elementos de Máquinas';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=lSxkjgBTncA', conteudo_texto = '<h2>Transferência de Calor</h2><p>Condução, convecção e radiação - mecanismos de troca térmica.</p><h3>🔥 Mecanismos de Transferência</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#f8d7da;padding:15px;border-radius:8px;''><h4>🧱 Condução</h4><p>Contato direto entre partículas</p><p><em>Sólidos principalmente</em></p></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>🌊 Convecção</h4><p>Movimento do fluido</p><p><em>Líquidos e gases</em></p></div><div style=''flex:1;min-width:200px;background:#d1ecf1;padding:15px;border-radius:8px;''><h4>☀️ Radiação</h4><p>Ondas eletromagnéticas</p><p><em>Não precisa de meio</em></p></div></div><h3>🧱 Condução - Lei de Fourier</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><div style=''text-align:center;padding:15px;background:#d4edda;border-radius:8px;''><h3 style=''color:#28a745;''>q = -k × A × (dT/dx)</h3></div><table style=''width:100%;border-collapse:collapse;margin-top:15px;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Variável</th><th style=''padding:10px;border:1px solid #ddd;''>Significado</th><th style=''padding:10px;border:1px solid #ddd;''>Unidade</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>q</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Taxa de calor</td><td style=''padding:10px;border:1px solid #ddd;''>W</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>k</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Condutividade térmica</td><td style=''padding:10px;border:1px solid #ddd;''>W/(m·K)</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>A</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Área</td><td style=''padding:10px;border:1px solid #ddd;''>m²</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>dT/dx</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Gradiente de temperatura</td><td style=''padding:10px;border:1px solid #ddd;''>K/m</td></tr></table></div><h3>📊 Condutividade Térmica (k)</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#28a745;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Material</th><th style=''padding:10px;border:1px solid #ddd;''>k (W/m·K)</th><th style=''padding:10px;border:1px solid #ddd;''>Classificação</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>Cobre</td><td style=''padding:10px;border:1px solid #ddd;''>400</td><td style=''padding:10px;border:1px solid #ddd;''>Excelente condutor</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''>Alumínio</td><td style=''padding:10px;border:1px solid #ddd;''>237</td><td style=''padding:10px;border:1px solid #ddd;''>Bom condutor</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>Aço</td><td style=''padding:10px;border:1px solid #ddd;''>50</td><td style=''padding:10px;border:1px solid #ddd;''>Condutor médio</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''>Vidro</td><td style=''padding:10px;border:1px solid #ddd;''>1</td><td style=''padding:10px;border:1px solid #ddd;''>Isolante</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>Ar</td><td style=''padding:10px;border:1px solid #ddd;''>0,026</td><td style=''padding:10px;border:1px solid #ddd;''>Excelente isolante</td></tr></table></div><h3>🌊 Convecção - Lei de Newton</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;''><div style=''text-align:center;padding:15px;background:#ffc107;border-radius:8px;''><h3>q = h × A × (Ts - T∞)</h3></div><p style=''margin-top:10px;''><strong>h</strong> = coeficiente de convecção (W/m²·K)</p><h4>Tipos:</h4><ul><li><strong>Natural:</strong> Movimento por diferença de densidade (h baixo)</li><li><strong>Forçada:</strong> Movimento por ventilador/bomba (h alto)</li></ul></div><h3>☀️ Radiação - Lei de Stefan-Boltzmann</h3><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;''><div style=''text-align:center;padding:15px;background:#17a2b8;color:white;border-radius:8px;''><h3>q = ε × σ × A × T⁴</h3></div><p style=''margin-top:10px;''><strong>ε</strong> = emissividade (0 a 1)</p><p><strong>σ</strong> = constante de Stefan-Boltzmann = 5,67 × 10⁻⁸ W/(m²·K⁴)</p><p><em>Corpo negro: ε = 1 (absorve/emite tudo)</em></p></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Na radiação, a temperatura está na <strong>quarta potência</strong>! Dobrar T significa multiplicar a emissão por 16 (2⁴)!</p></div>' WHERE titulo = 'Resumo: Transferência de Calor';
